  async stageFiles(files: string[]): Promise<void> {
    if (files.length === 0) {
      return;
    }
    const result = await this.pi.exec("git", ["add", "--", ...files]);
    if (result.code !== 0) {
      throw new Error(
        `git add failed (code ${result.code}): ${result.stderr.trim() || "Unknown error"}`,
      );
    }
  }
